create extension if not exists pgcrypto;
create type public.workspace_role as enum ('owner','admin','member','viewer');
create type public.permission_level as enum ('read_only','suggest_only','draft_only','execute_with_approval','execute_auto');
create type public.risk_level as enum ('low','medium','high','critical');
create type public.integration_status as enum ('connected','disconnected','needs_setup','error');
create type public.integration_health as enum ('healthy','degraded','failing','unknown');
create type public.room_status as enum ('active','planning','paused','archived');
create type public.agent_status as enum ('idle','planning','working','blocked','reviewing');
create type public.task_status as enum ('backlog','next','in_progress','review','done');
create type public.task_priority as enum ('low','medium','high','urgent');
create type public.workflow_status as enum ('active','draft','paused');
create type public.workflow_run_status as enum ('queued','running','completed','failed','waiting_for_approval');
create type public.approval_status as enum ('pending','approved','denied','expired');
create type public.actor_type as enum ('user','agent','integration','system');
create table public.users (id uuid primary key references auth.users(id) on delete cascade,email text not null unique,display_name text not null,avatar_url text,default_workspace_id uuid,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.workspaces (id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,owner_user_id uuid not null references public.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
alter table public.users add constraint users_default_workspace_id_fkey foreign key (default_workspace_id) references public.workspaces(id) on delete set null;
create table public.workspace_members (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,user_id uuid not null references public.users(id) on delete cascade,role public.workspace_role not null default 'member',created_at timestamptz not null default now(),unique(workspace_id,user_id));
create table public.rooms (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,name text not null,slug text not null,mission text not null default '',status public.room_status not null default 'planning',accent_color text,launch_progress int not null default 0 check (launch_progress between 0 and 100),created_by uuid references public.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workspace_id,slug));
create table public.agents (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,name text not null,role text not null,description text not null default '',status public.agent_status not null default 'idle',role_prompt text not null default '',tools jsonb not null default '[]',permission_level public.permission_level not null default 'suggest_only',is_template boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.room_agents (id uuid primary key default gen_random_uuid(),room_id uuid not null references public.rooms(id) on delete cascade,agent_id uuid not null references public.agents(id) on delete cascade,current_task text,status public.agent_status not null default 'idle',permission_override public.permission_level,memory_summary text not null default '',created_at timestamptz not null default now(),unique(room_id,agent_id));
create table public.integrations (id uuid primary key default gen_random_uuid(),key text not null unique,name text not null,category text not null,phase text not null,capabilities jsonb not null default '[]',high_risk_actions text[] not null default '{}',created_at timestamptz not null default now());
create table public.user_integrations (id uuid primary key default gen_random_uuid(),user_id uuid not null references public.users(id) on delete cascade,integration_id uuid not null references public.integrations(id) on delete cascade,status public.integration_status not null default 'needs_setup',health public.integration_health not null default 'unknown',permission_level public.permission_level not null default 'read_only',last_synced_at timestamptz,credentials_ref text,config jsonb not null default '{}',error_message text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(user_id,integration_id));
create table public.room_integrations (id uuid primary key default gen_random_uuid(),room_id uuid not null references public.rooms(id) on delete cascade,integration_id uuid not null references public.integrations(id) on delete cascade,user_integration_id uuid references public.user_integrations(id) on delete set null,status public.integration_status not null default 'needs_setup',health public.integration_health not null default 'unknown',last_synced_at timestamptz,settings jsonb not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(room_id,integration_id));
create table public.tasks (id uuid primary key default gen_random_uuid(),room_id uuid not null references public.rooms(id) on delete cascade,title text not null,description text not null default '',status public.task_status not null default 'backlog',priority public.task_priority not null default 'medium',due_date date,assigned_agent_id uuid references public.agents(id),external_links jsonb not null default '[]',created_by uuid references public.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.task_comments (id uuid primary key default gen_random_uuid(),task_id uuid not null references public.tasks(id) on delete cascade,author_user_id uuid references public.users(id),author_agent_id uuid references public.agents(id),body text not null,created_at timestamptz not null default now());
create table public.workflows (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,room_id uuid references public.rooms(id) on delete cascade,name text not null,description text not null default '',status public.workflow_status not null default 'draft',trigger_type text not null default 'manual',created_by uuid references public.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.workflow_steps (id uuid primary key default gen_random_uuid(),workflow_id uuid not null references public.workflows(id) on delete cascade,position int not null check(position>0),name text not null,action_type text not null,integration_key text,config jsonb not null default '{}',requires_approval boolean not null default false,unique(workflow_id,position));
create table public.workflow_runs (id uuid primary key default gen_random_uuid(),workflow_id uuid not null references public.workflows(id) on delete cascade,room_id uuid references public.rooms(id),status public.workflow_run_status not null default 'queued',started_by uuid references public.users(id),started_at timestamptz not null default now(),completed_at timestamptz,result jsonb not null default '{}');
create table public.activity_events (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,room_id uuid references public.rooms(id),actor_type public.actor_type not null,actor_id uuid,integration_key text,event_type text not null,title text not null,summary text not null default '',payload jsonb not null default '{}',risk_level public.risk_level not null default 'low',created_at timestamptz not null default now());
create table public.approvals (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,room_id uuid references public.rooms(id),requested_by_agent_id uuid references public.agents(id),action_type text not null,integration_key text,summary text not null,payload jsonb not null default '{}',risk_level public.risk_level not null default 'high',status public.approval_status not null default 'pending',requested_by uuid references public.users(id),reviewed_by uuid references public.users(id),requested_at timestamptz not null default now(),reviewed_at timestamptz);
create table public.files (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,room_id uuid references public.rooms(id),name text not null,file_type text not null,source_url text,integration_key text,external_id text,created_by uuid references public.users(id),created_at timestamptz not null default now());
create table public.agent_memory (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,room_id uuid references public.rooms(id),agent_id uuid not null references public.agents(id) on delete cascade,scope text not null,key text not null,value jsonb not null default '{}',source text not null default 'system',expires_at timestamptz,created_at timestamptz not null default now());
create table public.notifications (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,user_id uuid not null references public.users(id) on delete cascade,room_id uuid references public.rooms(id),activity_event_id uuid references public.activity_events(id),type text not null,title text not null,read_at timestamptz,created_at timestamptz not null default now());
create table public.audit_logs (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,actor_user_id uuid references public.users(id),actor_agent_id uuid references public.agents(id),action text not null,target_type text not null,target_id text not null,payload jsonb not null default '{}',created_at timestamptz not null default now());
create index activity_events_room_recent_idx on public.activity_events(room_id, created_at desc);
create index activity_events_workspace_recent_idx on public.activity_events(workspace_id, created_at desc);
create index tasks_room_board_idx on public.tasks(room_id, status, priority, updated_at desc);
create index approvals_pending_workspace_idx on public.approvals(workspace_id, requested_at desc) where status='pending';
create index room_integrations_room_status_health_idx on public.room_integrations(room_id,status,health);
create index agent_memory_lookup_idx on public.agent_memory(agent_id, room_id, scope, key);
create index audit_logs_workspace_recent_idx on public.audit_logs(workspace_id, created_at desc);
create or replace function public.is_workspace_member(target_workspace_id uuid) returns boolean language sql security definer set search_path=public as $$ select exists(select 1 from public.workspace_members wm where wm.workspace_id=target_workspace_id and wm.user_id=auth.uid()) $$;
create or replace function public.has_workspace_role(target_workspace_id uuid, allowed_roles public.workspace_role[]) returns boolean language sql security definer set search_path=public as $$ select exists(select 1 from public.workspace_members wm where wm.workspace_id=target_workspace_id and wm.user_id=auth.uid() and wm.role=any(allowed_roles)) $$;
alter table public.users enable row level security; alter table public.workspaces enable row level security; alter table public.workspace_members enable row level security; alter table public.rooms enable row level security; alter table public.agents enable row level security; alter table public.room_agents enable row level security; alter table public.user_integrations enable row level security; alter table public.room_integrations enable row level security; alter table public.tasks enable row level security; alter table public.task_comments enable row level security; alter table public.workflows enable row level security; alter table public.workflow_steps enable row level security; alter table public.workflow_runs enable row level security; alter table public.activity_events enable row level security; alter table public.approvals enable row level security; alter table public.files enable row level security; alter table public.agent_memory enable row level security; alter table public.notifications enable row level security; alter table public.audit_logs enable row level security;
create policy "Users read own profile" on public.users for select using (id=auth.uid());
create policy "Workspace members read workspace" on public.workspaces for select using (public.is_workspace_member(id));
create policy "Workspace members read rooms" on public.rooms for select using (public.is_workspace_member(workspace_id));
create policy "Workspace members write rooms" on public.rooms for all using (public.has_workspace_role(workspace_id, array['owner','admin','member']::public.workspace_role[])) with check (public.has_workspace_role(workspace_id, array['owner','admin','member']::public.workspace_role[]));
create policy "Workspace members read activity" on public.activity_events for select using (public.is_workspace_member(workspace_id));
create policy "Workspace members append activity" on public.activity_events for insert with check (public.is_workspace_member(workspace_id));
create policy "Workspace members read approvals" on public.approvals for select using (public.is_workspace_member(workspace_id));
create policy "Admins review approvals" on public.approvals for update using (public.has_workspace_role(workspace_id, array['owner','admin']::public.workspace_role[])) with check (public.has_workspace_role(workspace_id, array['owner','admin']::public.workspace_role[]));
create policy "Users manage own integrations" on public.user_integrations for all using (user_id=auth.uid()) with check (user_id=auth.uid());
-- RLS intent: room_agents, room_integrations, tasks, comments, workflows, files, memory, notifications, and audit logs follow workspace membership. Client deletes for activity_events and audit_logs should remain denied except through trusted server paths.
